import { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { toast } from 'react-toastify';
import { useAuth } from '../context/AuthContext';

export default function Register() {
  const [form, setForm] = useState({ name: '', email: '', password: '', role: 'backer' });
  const [loading, setLoading] = useState(false);
  const { register } = useAuth();
  const navigate = useNavigate();

  const handleChange = e => setForm({ ...form, [e.target.name]: e.target.value });

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const user = await register(form.name, form.email, form.password, form.role);
      toast.success(`Welcome, ${user.name}! Account created.`);
      navigate(`/${user.role}`);
    } catch (err) {
      toast.error(err.response?.data?.message || 'Registration failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center px-4" style={{ background: '#0a0d1a' }}>
      <div style={{ background: '#111827', border: '1px solid #1f2937', width: '100%', maxWidth: 440 }}
           className="p-8 rounded-2xl">
        <h1 style={{ fontFamily: 'Syne, sans-serif' }} className="text-2xl font-bold mb-1">Create Account</h1>
        <p className="text-gray-400 text-sm mb-8">Join BackerSphere X today</p>

        {/* Role selector */}
        <div className="grid grid-cols-2 gap-3 mb-6">
          {['backer', 'innovator'].map(r => (
            <button key={r} type="button" onClick={() => setForm({ ...form, role: r })}
              style={{
                border: form.role === r ? '1px solid #00d4aa' : '1px solid #374151',
                background: form.role === r ? 'rgba(0,212,170,0.08)' : '#0a0d1a',
                color: form.role === r ? '#00d4aa' : '#9ca3af'
              }}
              className="py-3 rounded-xl text-sm font-medium capitalize transition-all">
              {r === 'backer' ? '💰 Backer' : '🚀 Innovator'}
            </button>
          ))}
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-sm text-gray-400 mb-1.5">Full Name</label>
            <input name="name" value={form.name} onChange={handleChange} required
              style={{ background: '#0a0d1a', border: '1px solid #374151', color: 'white' }}
              className="w-full px-4 py-3 rounded-xl text-sm focus:outline-none focus:border-teal-500 transition-colors"
              placeholder="Your name" />
          </div>
          <div>
            <label className="block text-sm text-gray-400 mb-1.5">Email</label>
            <input name="email" type="email" value={form.email} onChange={handleChange} required
              style={{ background: '#0a0d1a', border: '1px solid #374151', color: 'white' }}
              className="w-full px-4 py-3 rounded-xl text-sm focus:outline-none focus:border-teal-500 transition-colors"
              placeholder="you@example.com" />
          </div>
          <div>
            <label className="block text-sm text-gray-400 mb-1.5">Password</label>
            <input name="password" type="password" value={form.password} onChange={handleChange} required minLength={6}
              style={{ background: '#0a0d1a', border: '1px solid #374151', color: 'white' }}
              className="w-full px-4 py-3 rounded-xl text-sm focus:outline-none focus:border-teal-500 transition-colors"
              placeholder="Min 6 characters" />
          </div>
          <button type="submit" disabled={loading}
            style={{ background: '#00d4aa', color: '#0a0d1a' }}
            className="w-full py-3 rounded-xl font-bold text-sm hover:opacity-90 transition-all disabled:opacity-60 mt-2">
            {loading ? 'Creating account...' : 'Create Account'}
          </button>
        </form>

        <p className="text-center text-gray-500 text-sm mt-6">
          Already have an account?{' '}
          <Link to="/login" style={{ color: '#00d4aa' }} className="hover:underline">Sign in</Link>
        </p>
      </div>
    </div>
  );
}
